built as (
  select i.recipe_en,
    jsonb_agg(jsonb_build_object('name_en',i.ing_en,'name_zh',ing.name_zh,'ingredient_id',ing.id,'grams',i.grams) order by i.ord) as items
  from imp i left join public.ingredients ing on lower(trim(ing.name_en))=lower(trim(i.ing_en))
  group by i.recipe_en
),
upd as (
  update public.recipes r set items=b.items, name_zh=coalesce(r.name_zh,rc.name_zh)
  from built b join rec rc on lower(trim(rc.name_en))=lower(trim(b.recipe_en))
  where lower(trim(r.name_en))=lower(trim(b.recipe_en))
  returning lower(trim(r.name_en)) as k
)
insert into public.recipes(id,name_en,name_zh,items,allergen_ids,owner_id,place_id)
select 'rec_menu_'||substr(md5(lower(trim(rc.name_en))),1,16), rc.name_en, rc.name_zh,
       coalesce(b.items,'[]'::jsonb), '[]'::jsonb, null, null
from (select distinct on (lower(trim(name_en))) name_en,name_zh from rec order by lower(trim(name_en))) rc
left join built b on lower(trim(b.recipe_en))=lower(trim(rc.name_en))
where not exists (select 1 from public.recipes r where lower(trim(r.name_en))=lower(trim(rc.name_en)));

-- verify: these recipes and how many ingredient lines linked to a real ingredient
select r.name_en,
  (select count(*) from jsonb_array_elements(r.items) e) as ings,
  (select count(*) from jsonb_array_elements(r.items) e where (e->>'ingredient_id') is not null) as linked
from public.recipes r
where lower(trim(r.name_en)) in (
  lower(trim('Alfredo pasta')),lower(trim('Apple Cake')),lower(trim('Applesauce quinoa bread')),lower(trim('Blanched veggies with ranch Greek yogurt dipping sauce')),lower(trim('Boston salmon cakes')),lower(trim('Braised Cabbage with Caraway Seeds')),lower(trim('Broccolis & blue cheese gratin')),lower(trim('Cauliflower crisp')),lower(trim('Cheesy flatbread')),lower(trim('Chicken parmesan meatballs')),lower(trim('Chocolate Cake')),lower(trim('Corn-oat bread')),lower(trim('Crunchy broccoli salad')),lower(trim('Dragon Fruits')),lower(trim('fresh delight yoghurt')),lower(trim('Lightly Seasoned Edamame')),lower(trim('Mandarins')),lower(trim('Quinoa and bean soft tacos')),lower(trim('Raw kale and Brussels sprouts salad with pear (or other seasonal fruit)')),lower(trim('Risotto with greens')),lower(trim('Roasted carrots')),lower(trim('Sautéed courgettes & Parmesan')),lower(trim('Skillet green beans')),lower(trim('Skillet scallops')),lower(trim('Steamed broccoli with roasted corn kernels')),lower(trim('Steamed Broccoli with Zucchini & Herb Vinaigrette')),lower(trim('Sweet and sour cabbage')),lower(trim('sweet potatoes puree')),lower(trim('tangerine')),lower(trim('Texas beans and rice'))
) order by r.name_en;
